#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int cmp_char(const void *a, const void *b) {
    return *(const char *)a - *(const char *)b;
}

void backtrack(const char *sorted, int n, int depth, int *used, char *curr, int *first) {
    if (depth == n) {
        curr[n] = '\0';
        if (!(*first)) printf(" ");
        printf("%s", curr);
        *first = 0;
        return;
    }
    for (int i = 0; i < n; ++i) {
        if (used[i]) continue;
        if (i > 0 && sorted[i] == sorted[i-1] && !used[i-1]) continue; // skip duplicates
        used[i] = 1;
        curr[depth] = sorted[i];
        backtrack(sorted, n, depth + 1, used, curr, first);
        used[i] = 0;
    }
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char s[20];
        scanf("%s", s);
        int n = strlen(s);
        qsort(s, n, sizeof(char), cmp_char);
        int used[20] = {0};
        char curr[20];
        int first = 1;
        backtrack(s, n, 0, used, curr, &first);
        printf("\n");
    }
    return 0;
}

