import java.io.*;
import java.util.*;
public class Main {
    private static void backtrack(char[] sorted, boolean[] used, char[] cur, int depth, StringBuilder out) {
        if (depth == sorted.length) {
            out.append(new String(cur)).append(' ');
            return;
        }
        for (int i = 0; i < sorted.length; i++) {
            if (used[i]) continue;
            if (i > 0 && sorted[i] == sorted[i - 1] && !used[i - 1]) continue; // skip duplicates
            used[i] = true;
            cur[depth] = sorted[i];
            backtrack(sorted, used, cur, depth + 1, out);
            used[i] = false;
        }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder totalOut = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            String s = br.readLine().trim();
            char[] arr = s.toCharArray();
            Arrays.sort(arr);
            boolean[] used = new boolean[arr.length];
            char[] cur = new char[arr.length];
            StringBuilder out = new StringBuilder();
            backtrack(arr, used, cur, 0, out);
            if (out.length() > 0 && out.charAt(out.length() - 1) == ' ') out.setLength(out.length() - 1);
            totalOut.append(out);
            if (tc != T - 1) totalOut.append('\n');
        }
        System.out.print(totalOut.toString());
    }
}

