const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(lines[idx++].trim(), 10);
let outputs = [];
for (let tc = 0; tc < T; tc++) {
  const s = lines[idx++].trim();
  const chars = s.split('').sort();
  const n = chars.length;
  const used = new Array(n).fill(false);
  const cur = new Array(n);
  const res = [];
  function backtrack(depth) {
    if (depth === n) {
      res.push(cur.join(''));
      return;
    }
    for (let i = 0; i < n; i++) {
      if (used[i]) continue;
      if (i > 0 && chars[i] === chars[i - 1] && !used[i - 1]) continue; // skip duplicates
      used[i] = true;
      cur[depth] = chars[i];
      backtrack(depth + 1);
      used[i] = false;
    }
  }
  backtrack(0);
  outputs.push(res.join(' '));
}
